#include<bits/stdc++.h>
#define rep(a,b,c) for(int c=(a);c<=(b);++c)
#define drep(a,b,c) for(int c=(a);c>=(b);--c)
#define grep(a,b,c) for(int c=a.head[(b)];c;c=a.nxt[c])
#define int long long
using namespace std;
inline int read()
{
	int res=0; char ch=getchar(); bool flag=0;
	while(ch<'0'||ch>'9')flag^=(ch=='-'),ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();
	return flag ? -res : res ;
}
const int N=1e5+10,M=2e5+10,INF=0x7fffffff;
struct Gragh
{
	int head[N],des[M],cst[M],cap[M],nxt[M],cnt;
	inline void ins(int x,int y,int z,int c){des[++cnt]=y;nxt[cnt]=head[x];cap[cnt]=z;cst[cnt]=c;head[x]=cnt;}
	inline void Init(){memset(head,0,sizeof(head));cnt=1;}
}a;
int s,t,que[N],H,T,dis[N],mnf[N],pre[N];bool inq[N];
inline bool spfa()
{
	memset(dis,0x7f,sizeof(dis));dis[s]=0;
	mnf[s]=dis[0];inq[que[H=T=1]=s]=1;while(H<=T)
	{
		int u;inq[u=que[H++]]=0;grep(a,u,i)
		{
			int v=a.des[i];if(a.cap[i]&&dis[u]+a.cst[i]<dis[v])
			{
				dis[v]=dis[u]+a.cst[i];mnf[v]=min(mnf[u],a.cap[i]);
				pre[v]=i;if(!inq[v])inq[que[++T]=v]=1;
			}
		}
	}return dis[t]!=dis[0];
}
inline void update(int &mxf,int &mnc)
{
	int v=t;while(v^s){int i=pre[v];a.cap[i]-=mnf[t];a.cap[i^1]+=mnf[t];v=a.des[i^1];}
	mxf+=mnf[t];mnc+=dis[t]*mnf[t];return;
}
inline void EK(int u,int v,int &mnc,int &mxf){s=u,t=v;while(spfa())update(mnc,mxf);return;}
inline void Ins(int x,int y,int z,int c){a.ins(x,y,z,c);a.ins(y,x,0,-c);return;}
signed main()
{
	int n=read();a.Init();int S=n*2+1,T=n*2+2;
	rep(1,n,i){int z=read();Ins(S,i,z,0);Ins(i+n,T,z,0);}
	int m=read(),t1=read(),m1=read(),t2=read(),m2=read();
	rep(1,n,i)
	{
		if(i+1<=n)Ins(i,i+1,INF,0);if(i+t1<=n)Ins(i,i+n+t1,INF,m1);
		if(i+t2<=n)Ins(i,i+n+t2,INF,m2);Ins(S,i+n,INF,m);
	}
//	rep(1,n*2+2,i)grep(a,i,j)printf("%d %d %d\n",i,a.des[j],a.cap[j]);
	int ans1=0,ans2=0;EK(S,T,ans1,ans2);printf("%lld\n",ans2);
	return 0;
}
